1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return an empty result for an empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells with one neighbor each (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block unchanged (still life: survival)", () => {
15	    const sortCells = (cells: [number, number][]) =>
16	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
17	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
18	    expect(sortCells(nextGeneration(block))).toEqual(sortCells(block));
19	  });
20	  it.todo("should kill a cell with more than three neighbors (overpopulation)");
21	  it.todo("should bring a dead cell with exactly three neighbors to life (reproduction)");
22	  it.todo("should transform a vertical blinker into a horizontal blinker, including negative coordinates");
23	});
24

1	export type Cell = [number, number];
2	
3	const isNeighbor = (a: Cell, b: Cell): boolean => {
4	  const dx = Math.abs(a[0] - b[0]);
5	  const dy = Math.abs(a[1] - b[1]);
6	  return (dx !== 0 || dy !== 0) && dx <= 1 && dy <= 1;
7	};
8	
9	const countLiveNeighbors = (cell: Cell, cells: Cell[]): number =>
10	  cells.filter((other) => isNeighbor(cell, other)).length;
11	
12	const survives = (liveNeighbors: number): boolean =>
13	  liveNeighbors === 2 || liveNeighbors === 3;
14	
15	export const nextGeneration = (cells: Cell[]): Cell[] =>
16	  cells.filter((cell) => survives(countLiveNeighbors(cell, cells)));
